// Get the input item with binary data
const item = $input.item.json;
const binaryData = $input.item.binary;

// Get the CSV content from binary data
let csvContent;
try {
  const fileData = await this.helpers.getBinaryDataBuffer(0, 'data');
  csvContent = fileData.toString('utf-8');
} catch (error) {
  throw new Error('Failed to read binary data: ' + error.message);
}

// Helper function to parse CSV line with quoted field support
function parseCSVLine(line) {
  const result = [];
  let current = '';
  let inQuotes = false;

  for (let i = 0; i < line.length; i++) {
    const char = line[i];

    if (char === '"') {
      inQuotes = !inQuotes;
    } else if (char === ',' && !inQuotes) {
      result.push(current.trim());
      current = '';
    } else {
      current += char;
    }
  }
  result.push(current.trim());
  return result;
}

// Split into lines and parse
const lines = csvContent.trim().split('\n');
const headers = parseCSVLine(lines[0]);

// Build output items
const outputItems = [];
for (let i = 1; i < lines.length; i++) {
  const line = lines[i].trim();
  if (line) {
    const values = parseCSVLine(line);
    const ticket = {};
    headers.forEach((header, index) => {
      ticket[header] = values[index] || '';
    });
    outputItems.push({ json: ticket });
  }
}

return outputItems;

// Extract the AI response from Gemini
const response = $input.item.json;

// Gemini returns the response in candidates[0].content.parts[0].text
const aiText = response.candidates[0].content.parts[0].text;

// Parse the JSON from the AI response
let classification;
try {
  classification = JSON.parse(aiText);
} catch (error) {
  throw new Error('Failed to parse AI response as JSON: ' + aiText);
}

// Combine original ticket data with classification
const result = {
  ticket_id: $input.item.json.ticket_id || $('Parse CSV').item.json.ticket_id,
  created_at: $input.item.json.created_at || $('Parse CSV').item.json.created_at,
  customer_name: $input.item.json.customer_name || $('Parse CSV').item.json.customer_name,
  customer_email: $input.item.json.customer_email || $('Parse CSV').item.json.customer_email,
  subject: $input.item.json.subject || $('Parse CSV').item.json.subject,
  body: $input.item.json.body || $('Parse CSV').item.json.body,
  status: $input.item.json.status || $('Parse CSV').item.json.status,
  urgency: classification.urgency,
  category: classification.category,
  summary: classification.summary,
  flag_for_review: classification.flag_for_review
};

return { json: result };
